def is_balanced(s):
    stack = []
    mapping = {')': '(', ']': '[', '}': '{'}
    for char in s:
        if char in mapping:
            if not stack:
                return False
            top = stack.pop()
            if top != mapping[char]:
                return False
        elif char in '({[':
            stack.append(char)
    return not stack
